import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

const InteractionMode = () => {
    const navigate = useNavigate();
    const location = useLocation();

    // Retrieve the selected avatar passed via state
    const { avatar } = location.state || { avatar: null };

    // Map videos for each avatar
    const avatarVideos = {
        goldfish: "/videos/goldfish-video.mp4",
        parrot: "/videos/parrot-video.mp4",
        cat: "/videos/cat-video.mp4",
        dog: "/videos/dog-video.mp4",
    };

    // Debugging: Log the selected avatar name
    console.log("Selected Avatar Name:", avatar?.name);

    // Normalize avatar name to find the corresponding video
    const videoKey = avatar?.name?.toLowerCase().trim();
    const videoSrc = avatarVideos[videoKey];

    return (
        <div style={{ textAlign: "center", padding: "50px" }}>
            <h1>Choose your mode of interaction</h1>
            <div style={{ display: "flex", justifyContent: "center", gap: "30px", marginTop: "30px" }}>
                {/* Interaction */}
                <div
                    onClick={() => navigate("/interaction-page")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    {videoSrc ? (
                        <video
                            src={videoSrc}
                            autoPlay
                            loop
                            muted
                            style={{
                                width: "100%",
                                height: "150px",
                                objectFit: "cover",
                                borderRadius: "8px",
                            }}
                        />
                    ) : (
                        <div
                            style={{
                                width: "100%",
                                height: "150px",
                                backgroundColor: "#dfe7fd",
                                borderRadius: "8px",
                                display: "flex",
                                justifyContent: "center",
                                alignItems: "center",
                            }}
                        >
                            <p style={{ fontSize: "18px", fontWeight: "bold" }}>No Video Available</p>
                        </div>
                    )}
                    <p style={{ marginTop: "10px" }}>Interaction</p>
                </div>

                {/* Health Check-In */}
                <div
                    onClick={() => navigate("/health-check")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    {avatar ? (
                        <img
                            src={avatar.image}
                            alt={avatar.name}
                            style={{
                                width: "100%",
                                height: "150px",
                                objectFit: "cover",
                                borderRadius: "8px",
                            }}
                        />
                    ) : (
                        <div
                            style={{
                                width: "100%",
                                height: "150px",
                                backgroundColor: "#fdebd0",
                                borderRadius: "8px",
                                display: "flex",
                                justifyContent: "center",
                                alignItems: "center",
                            }}
                        >
                            <p style={{ fontSize: "18px", fontWeight: "bold" }}>No Avatar Selected</p>
                        </div>
                    )}
                    <p style={{ marginTop: "10px" }}>Health Check-In</p>
                </div>
            </div>
        </div>
    );
};

export default InteractionMode;
